class Solution:
    def rotatedDigits(self, n):
        invalid = set('347')
        flips = set('2569')
        count = 0
        for x in range(1, n + 1):
            digs = str(x)
            if any(d in invalid for d in digs):
                continue
            if any(d in flips for d in digs):
                count += 1
        return count

solutions.python:
class Solution:
    def rotatedDigits(self, n):
        good = 0
        for x in range(1, n + 1):
            has_flip = False
            valid = True
            y = x
            while y > 0:
                d = y % 10
                if d in (3, 4, 7):
                    valid = False
                    break
                if d in (2, 5, 6, 9):
                    has_flip = True
                y //= 10
            if valid and has_flip:
                good += 1
        return good

