var rotatedDigits = function(n) {
    let good = 0;
    for (let x = 1; x <= n; x++) {
        let hasFlip = false;
        let valid = true;
        let y = x;
        while (y > 0) {
            const d = y % 10;
            if (d === 3 || d === 4 || d === 7) { valid = false; break; }
            if (d === 2 || d === 5 || d === 6 || d === 9) hasFlip = true;
            y = Math.floor(y / 10);
        }
        if (valid && hasFlip) good++;
    }
    return good;
};
